package com.questkeeper.command;
import com.questkeeper.gui.GuiManager; import com.questkeeper.message.MessageManager; import com.questkeeper.quest.QuestManager; import com.questkeeper.quest.service.QuestClaimService; import org.bukkit.command.*; import org.bukkit.entity.Player; import java.util.*;
public final class QuestCommand implements CommandExecutor,TabCompleter {private final GuiManager guis;private final QuestClaimService claims;private final QuestManager quests;private final MessageManager messages;public QuestCommand(GuiManager g,QuestClaimService c,QuestManager q,MessageManager m){guis=g;claims=c;quests=q;messages=m;}public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(!(s instanceof Player p)){s.sendMessage("Players only.");return true;}if(!p.hasPermission("questkeeper.quests")){messages.send(p,"no-permission",Map.of());return true;}if(a.length==2&&a[0].equalsIgnoreCase("cancel")){claims.cancel(p,a[1]);return true;}guis.openJournal(p);return true;}public List<String> onTabComplete(CommandSender s,Command c,String l,String[] a){if(a.length==1)return List.of("active","completed","tracked","help","cancel");if(a.length==2&&a[0].equalsIgnoreCase("cancel"))return quests.all().stream().map(q->q.id()).toList();return List.of();}}
